import sys

def find_substring_occurrences(text, substring):
    occurrences = []
    lines = text.split('\n')
    for line in lines:
        start = 0
        while True:
            start = line.find(substring, start)
            if start == -1:
                break
            occurrences.append(line[start:start+len(substring)])
            start += len(substring)
    return '\n'.join(occurrences)

if __name__ == "__main__":
    text = sys.argv[1]
    substring = sys.argv[2]
    result = find_substring_occurrences(text, substring)
    print(result)

