def format_size(size):
    units = ['B', 'KB', 'MB', 'GB', 'TB']
    for unit in units:
        if size < 1024:
            return f"{size:.2f} {unit}\n"
        size /= 1024

if __name__ == "__main__":
    if len(sys.argv) != 2:
        print("Usage: python script.py <non-negative integer>")
        sys.exit(1)

