import sys

def extract_urls(text):
    urls = []
    i = 0
    while i < len(text):
        if text[i:i+7] == "http://" or text[i:i+8] == "https://":
            start = i
            while i < len(text) and not text[i].isspace():
                i += 1
            urls.append(text[start:i])
        else:
            i += 1
    return urls

if __name__ == "__main__":
    if len(sys.argv) > 1:
        input_text = sys.argv[1]
        urls = extract_urls(input_text)
        for url in urls:
            print(url)

