import sys

def octal_to_symbolic(octal):
    permissions = 'rwx'
    symbolic = ''
    for digit in octal:
        for i in range(3):
            if int(digit) & (1 << (2 - i)):
                symbolic += permissions[i]
            else:
                symbolic += '-'
        symbolic += ' '
    return symbolic.strip() + '\n'

if __name__ == "__main__":
    if len(sys.argv) != 2 or not sys.argv[1].isdigit() or len(sys.argv[1]) != 3:
        print("Usage: python script.py <3-digit octal permission>")
    else:
        print(octal_to_symbolic(sys.argv[1]))

