def count_tokens(args):
    token_count = {}
    for arg in args[1:]:
        if arg in token_count:
            token_count[arg] += 1
        else:
            token_count[arg] = 1
    sorted_tokens = sorted(token_count.items())
    result = ' '.join(f'{name}={count}' for name, count in sorted_tokens)
    print(result)

